1939: // mfaAuthChallenge constructs an MFAAuthenticateChallenge for all MFA devices
1940: // registered by the user.
1941: func (a *Server) mfaAuthChallenge(ctx context.Context, user string, u2fStorage u2f.AuthenticationStorage) (*proto.MFAAuthenticateChallenge, error) {
1942: 	// Check what kind of MFA is enabled.
1943: 	apref, err := a.GetAuthPreference()
1944: 	if err != nil {
1945: 		return nil, trace.Wrap(err)
1946: 	}
1947: 	var enableTOTP, enableU2F bool
1948: 	switch apref.GetType() {
1949: 	case teleport.TOTP:
1950: 		enableTOTP, enableU2F = true, false
1951: 	case teleport.U2F:
1952: 		enableTOTP, enableU2F = false, true
1953: 	default:
1954: 		// Other AuthPreference types don't restrict us to a single MFA type,
1955: 		// send all challenges.
1956: 		enableTOTP, enableU2F = true, true
1957: 	}
1958: 	var u2fPref *types.U2F
1959: 	if enableU2F {
1960: 		u2fPref, err = apref.GetU2F()
1961: 		if trace.IsNotFound(err) {
1962: 			// If U2F parameters were not set in the auth server config,
1963: 			// disable U2F challenges.
1964: 			enableU2F = false
1965: 		} else if err != nil {
1966: 			return nil, trace.Wrap(err)
1967: 		}
1968: 	}
1969: 
1970: 	devs, err := a.GetMFADevices(ctx, user)
1971: 	if err != nil {
1972: 		return nil, trace.Wrap(err)
1973: 	}
1974: 
1975: 	challenge := new(proto.MFAAuthenticateChallenge)
1976: 	for _, dev := range devs {
1977: 		switch dev.Device.(type) {
1978: 		case *types.MFADevice_Totp:
1979: 			if !enableTOTP {
1980: 				continue
1981: 			}
1982: 			challenge.TOTP = new(proto.TOTPChallenge)
1983: 		case *types.MFADevice_U2F:
1984: 			if !enableU2F {
1985: 				continue
1986: 			}
1987: 			ch, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
1988: 				AppConfig:  *u2fPref,
1989: 				Dev:        dev,
1990: 				Storage:    u2fStorage,
1991: 				StorageKey: user,
1992: 			})
1993: 			if err != nil {
1994: 				return nil, trace.Wrap(err)
1995: 			}
1996: 			challenge.U2F = append(challenge.U2F, &proto.U2FChallenge{
1997: 				KeyHandle: ch.KeyHandle,
1998: 				Challenge: ch.Challenge,
1999: 				AppID:     ch.AppID,
2000: 			})
2001: 		default:
2002: 			log.Warningf("skipping MFA device of unknown type %T", dev.Device)
2003: 		}
2004: 	}
2005: 	return challenge, nil
2006: }
