	"github.com/gravitational/trace"
	"github.com/stretchr/testify/require"
	tstranexu2f "github.com/tstranex/u2f"
)

// TestRegression tests for multi-device U2F authentication issues.
// This regression test covers:
// 1. Multi-device U2F challenges are properly generated for all registered devices
// 2. MFA device management handles multi-device transitions correctly
// 3. Client/server compatibility for U2F challenge negotiation
func TestRegression(t *testing.T) {
	ctx := context.Background()
	utils.InitLoggerForTests(testing.Verbose())

	// Setup: Create auth server with U2F enabled
	bk, err := memory.New(memory.Config{})
	require.NoError(t, err)

	clusterName, err := services.NewClusterName(services.ClusterNameSpecV2{
		ClusterName: "test.localhost",
	})
	require.NoError(t, err)

	authConfig := &auth.InitConfig{
		ClusterName:            clusterName,
		Backend:                bk,
		Authority:              testauthority.New(),
		SkipPeriodicOperations: true,
	}
	server, err := auth.NewServer(authConfig)
	require.NoError(t, err)

	// Enable U2F in auth preferences
	authPref, err := services.NewAuthPreference(services.AuthPreferenceSpecV2{
		Type:         teleport.U2F,
		SecondFactor: teleport.U2F,
		U2F: &types.U2F{
			AppID: "https://localhost",
			Facets: []string{
				"https://localhost",
			},
		},
	})
	require.NoError(t, err)
	err = server.SetAuthPreference(ctx, authPref)
	require.NoError(t, err)

	// Create a user
	user, err := services.NewUser("testuser")
	require.NoError(t, err)
	user.SetRoles([]string{"admin"})
	err = server.UpsertUser(user)
	require.NoError(t, err)

	// Set password for the user
	err = server.UpsertPassword("testuser", []byte("password"))
	require.NoError(t, err)

	t.Run("MultiDeviceU2FChallenges", func(t *testing.T) {
		testMultiDeviceU2FChallenges(t, ctx, server, "testuser")
	})

	t.Run("MFADeviceManagement", func(t *testing.T) {
		testMFADeviceManagement(t, ctx, server, "testuser")
	})

	t.Run("ClientServerCompatibility", func(t *testing.T) {
		testClientServerCompatibility(t, ctx, server, "testuser")
	})
}

// testMultiDeviceU2FChallenges verifies that when a user has multiple U2F devices,
// the server correctly generates challenges for all of them.
func testMultiDeviceU2FChallenges(t *testing.T, ctx context.Context, server *auth.Server, username string) {
	// Create two U2F device registrations
	device1, err := createMockU2FDevice(ctx, server, username, "device1")
	require.NoError(t, err)
	require.NotNil(t, device1)

	device2, err := createMockU2FDevice(ctx, server, username, "device2")
	require.NoError(t, err)
	require.NotNil(t, device2)

	// Verify both devices are registered
	devices, err := server.GetMFADevices(ctx, username)
	require.NoError(t, err)
	require.Equal(t, 2, len(devices), "Expected 2 U2F devices to be registered")

	// Request U2F sign challenge (authentication)
	challenge, err := server.U2FSignRequest(username, []byte("password"))
	require.NoError(t, err)
	require.NotNil(t, challenge)

	// BUG: The Challenges array should contain challenges for BOTH devices
	// Currently, the code may only return one challenge
	require.Greater(t, len(challenge.Challenges), 0, "Expected at least one U2F challenge")

	// EXPECTED: With multiple devices registered, we should have multiple challenges
	// This test will fail if the server only returns a single challenge when multiple
	// devices are registered.
	if len(challenge.Challenges) < 2 {
		t.Logf("BUG DETECTED: Expected %d challenges (one per device), but got %d",
			2, len(challenge.Challenges))
		t.Fail()
	}

	// Verify each challenge has the required fields
	for i, ch := range challenge.Challenges {
		require.NotEmpty(t, ch.Challenge, "Challenge %d: Challenge field should not be empty", i)
		require.NotEmpty(t, ch.AppID, "Challenge %d: AppID field should not be empty", i)
		require.NotEmpty(t, ch.KeyHandle, "Challenge %d: KeyHandle field should not be empty", i)
	}

	// Verify backward compatibility: the embedded AuthenticateChallenge should be set
	// (for compatibility with pre-6.0 clients)
	require.NotNil(t, challenge.AuthenticateChallenge,
		"Embedded AuthenticateChallenge should be set for backward compatibility")
}

// testMFADeviceManagement verifies that adding and removing multiple devices works correctly
func testMFADeviceManagement(t *testing.T, ctx context.Context, server *auth.Server, username string) {
	// Start with one device
	device1, err := createMockU2FDevice(ctx, server, username, "mgmt-device1")
	require.NoError(t, err)

	devices, err := server.GetMFADevices(ctx, username)
	require.NoError(t, err)
	initialCount := len(devices)

	// Add a second device
	device2, err := createMockU2FDevice(ctx, server, username, "mgmt-device2")
	require.NoError(t, err)

	devices, err = server.GetMFADevices(ctx, username)
	require.NoError(t, err)
	require.Equal(t, initialCount+2, len(devices),
		"Expected one additional device after registration")

	// Add a third device
	device3, err := createMockU2FDevice(ctx, server, username, "mgmt-device3")
	require.NoError(t, err)

	devices, err = server.GetMFADevices(ctx, username)
	require.NoError(t, err)
	require.Equal(t, initialCount+3, len(devices),
		"Expected two additional devices after second registration")

	// Verify all three devices are distinct
	require.NotEqual(t, device1.GetName(), device2.GetName())
	require.NotEqual(t, device2.GetName(), device3.GetName())
	require.NotEqual(t, device1.GetName(), device3.GetName())

	// Delete the first device
	err = server.DeleteMFADevice(ctx, username, device1.GetName())
	require.NoError(t, err)

	devices, err = server.GetMFADevices(ctx, username)
	require.NoError(t, err)
	require.Equal(t, initialCount+2, len(devices),
		"Expected device count to decrease after deletion")

	// Verify the deleted device is gone
	for _, dev := range devices {
		require.NotEqual(t, device1.GetName(), dev.GetName(),
			"Deleted device should not be in the list")
	}

	// Verify remaining devices are still there
	foundDevice2 := false
	foundDevice3 := false
	for _, dev := range devices {
		if dev.GetName() == device2.GetName() {
			foundDevice2 = true
		}
		if dev.GetName() == device3.GetName() {
			foundDevice3 = true
		}
	}
	require.True(t, foundDevice2, "Device 2 should still be registered")
	require.True(t, foundDevice3, "Device 3 should still be registered")
}

// testClientServerCompatibility tests backward compatibility when clients and servers
// have different versions regarding multi-device U2F support
func testClientServerCompatibility(t *testing.T, ctx context.Context, server *auth.Server, username string) {
	// Create two devices
	device1, err := createMockU2FDevice(ctx, server, username, "compat-device1")
	require.NoError(t, err)
	device2, err := createMockU2FDevice(ctx, server, username, "compat-device2")
	require.NoError(t, err)

	// Get the challenge from the server (new format with multiple devices)
	challenge, err := server.U2FSignRequest(username, []byte("password"))
	require.NoError(t, err)

	// Simulate old client behavior: only use the embedded AuthenticateChallenge
	// (not the Challenges array). This is what pre-6.0 clients would do.
	oldClientChallenge := challenge.AuthenticateChallenge
	require.NotNil(t, oldClientChallenge,
		"Embedded challenge should be present for old client compatibility")

	// Old clients should be able to use the embedded challenge
	// and get a response that the server can verify
	require.NotEmpty(t, oldClientChallenge.Challenge)
	require.NotEmpty(t, oldClientChallenge.AppID)
	require.NotEmpty(t, oldClientChallenge.KeyHandle)

	// Test JSON marshaling/unmarshaling (simulating wire protocol)
	challengeJSON, err := json.Marshal(challenge)
	require.NoError(t, err)

	// Unmarshal back
	var unmarshaledChallenge auth.U2FAuthenticateChallenge
	err = json.Unmarshal(challengeJSON, &unmarshaledChallenge)
	require.NoError(t, err)

	// Verify the challenges array is preserved
	require.Greater(t, len(unmarshaledChallenge.Challenges), 0,
		"Challenges array should be preserved after JSON round-trip")

	// The number of challenges should match the number of devices
	devices, err := server.GetMFADevices(ctx, username)
	require.NoError(t, err)
	u2fDeviceCount := 0
	for _, d := range devices {
		if d.GetU2F() != nil {
			u2fDeviceCount++
		}
	}

	// BUG: If this fails, it means the server is not returning challenges for all devices
	if len(unmarshaledChallenge.Challenges) != u2fDeviceCount {
		t.Logf("BUG DETECTED: Challenge count mismatch. Expected %d challenges (one per U2F device), got %d",
			u2fDeviceCount, len(unmarshaledChallenge.Challenges))
		t.Fail()
	}
}

// createMockU2FDevice creates a mock U2F device for testing
func createMockU2FDevice(ctx context.Context, server *auth.Server, username, deviceName string) (*types.MFADevice, error) {
	// Create a mock U2F device
	mockU2F := mocku2f.NewMockU2F()

	// Get auth preferences for U2F config
	cap, err := server.GetAuthPreference()
	if err != nil {
		return nil, trace.Wrap(err)
	}
	u2fCfg, err := cap.GetU2F()
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Create in-memory storage for this registration
	storage, err := u2f.InMemoryRegistrationStorage(server.Identity)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Initialize registration
	regChallenge, err := u2f.RegisterInit(u2f.RegisterInitParams{
		StorageKey: username,
		AppConfig:  *u2fCfg,
		Storage:    storage,
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Simulate U2F device registration
	mockKey, err := mockU2F.RegisterKeyWithChallenge(&tstranexu2f.RegisterRequest{
		Challenge: regChallenge.Challenge,
		AppID:     regChallenge.AppID,
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Get the registration response from the mock device
	regResp, err := mockKey.RegisterResponse(&tstranexu2f.RegisterRequest{
		Challenge: regChallenge.Challenge,
		AppID:     regChallenge.AppID,
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Verify the registration and create the MFA device
	dev, err := u2f.RegisterVerify(ctx, u2f.RegisterVerifyParams{
		DevName:                    deviceName,
		Resp:                       *regResp,
		ChallengeStorageKey:        username,
		RegistrationStorageKey:     username,
		Storage:                    storage,
		Clock:                      server.GetClock(),
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Upsert the device
	err = server.UpsertMFADevice(ctx, username, dev)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	return dev, nil
}

