		DevName:                    deviceName,
		Resp:                       *regResp,
		ChallengeStorageKey:        username,
		RegistrationStorageKey:     username,
		Storage:                    storage,
		Clock:                      server.GetClock(),
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Upsert the device
	err = server.UpsertMFADevice(ctx, username, dev)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	return dev, nil
}
