// testClientServerCompatibility tests backward compatibility between
// different client and server versions regarding multi-device U2F support.
//
// BUG DESCRIPTION:
// The server sends U2F challenges in two formats:
// 1. Embedded "AuthenticateChallenge" field (for pre-6.0 clients)
// 2. "Challenges" array (for 6.0+ clients with multi-device support)
//
// The issue is that when both are present, the embedded field might
// only contain the challenge for the FIRST device, causing old clients
// to work but new clients to potentially miss challenges for other devices.
func testClientServerCompatibility(t *testing.T) {
	// Simulate a U2FAuthenticateChallenge response with multiple devices
	response := map[string]interface{}{
		"AuthenticateChallenge": map[string]string{
			"challenge":  "challenge1",
			"app_id":     "https://localhost",
			"key_handle": "device1_keyhandle",
		},
		"Challenges": []map[string]string{
			{
				"challenge":  "challenge1",
				"app_id":     "https://localhost",
				"key_handle": "device1_keyhandle",
			},
			{
				"challenge":  "challenge2",
				"app_id":     "https://localhost",
				"key_handle": "device2_keyhandle",
			},
			{
				"challenge":  "challenge3",
				"app_id":     "https://localhost",
				"key_handle": "device3_keyhandle",
			},
		},
	}

	// Test 1: Verify challenges array is properly serialized
	jsonBytes, err := json.Marshal(response)
	if err != nil {
		t.Logf("❌ Serialization error: %v", err)
		t.Fail()
		return
	}

	// Test 2: Verify deserialization preserves all challenges
	var deserializedResponse map[string]interface{}
	err = json.Unmarshal(jsonBytes, &deserializedResponse)
	if err != nil {
		t.Logf("❌ Deserialization error: %v", err)
		t.Fail()
		return
	}

	// Test 3: Verify Challenges array is intact
	if challenges, ok := deserializedResponse["Challenges"].([]interface{}); ok {
		expectedCount := 3
		if len(challenges) != expectedCount {
			t.Logf("❌ BUG: Expected %d challenges after deserialization, got %d",
				expectedCount, len(challenges))
			t.Fail()
		} else {
			t.Logf("✓ PASS: Challenges array preserved through JSON round-trip")
		}
	} else {
		t.Logf("❌ BUG: Challenges array not found or wrong type after deserialization")
		t.Fail()
	}

	// Test 4: Verify old clients can still use embedded challenge
	if embedded, ok := deserializedResponse["AuthenticateChallenge"].(map[string]interface{}); ok {
		if _, hasChallenge := embedded["challenge"]; hasChallenge {
			t.Logf("✓ PASS: Embedded AuthenticateChallenge present for backward compatibility")
		} else {
			t.Logf("❌ BUG: Embedded AuthenticateChallenge missing required fields")
			t.Fail()
		}
	} else {
		t.Logf("❌ BUG: AuthenticateChallenge field missing or wrong type")
		t.Fail()
	}
}

